/**
 * Feature flags — single source of truth
 * Source: hq_ff_feature_flags_mst (Supabase remote)
 * Regenerate: Supabase MCP execute_sql → scripts/extract-flag-catalog.js → scripts/generate-flag-catalog.js
 * Sync with database when adding or changing flags.
 */

import type { FeatureFlags } from '@/lib/types/tenant';

// ========================
// Catalog Types
// ========================

export type PlanBindingType = 'plan_bound' | 'independent';
export type FlagDataType = 'boolean' | 'integer' | 'string' | 'object';

export type GovernanceCategory = 'tenant_feature' | 'tenant_limit' | 'hq_feature' | 'hq_config' | 'experimental' | 'beta';

export interface FlagCatalogEntry {
  flag_key: string;
  flag_name: string;
  plan_binding_type: PlanBindingType;
  data_type: FlagDataType;
  default_value: boolean | number | string | Record<string, unknown>;
  /** UI grouping (from hq_ff_feature_flags_mst.ui_group) */
  ui_group?: string;
  /** Governance category (tenant_feature, tenant_limit, hq_feature, etc.) */
  governance_category?: GovernanceCategory;
  /** Display order within ui_group */
  ui_display_order?: number;
}

export type TenantSettingDefaultValue = boolean | number | string | Record<string, unknown>;
export type FeatureFlagKey = keyof FeatureFlags;

