/** All flag keys for batch RPC (hq_ff_get_effective_values_batch) */
export const ALL_FLAG_KEYS = FLAG_CATALOG.map((e) => e.flag_key);

export const FLAG_KEYS_PLAN_BOUND = FLAG_CATALOG.filter(
  (e) => e.plan_binding_type === 'plan_bound'
).map((e) => e.flag_key);

export const FLAG_KEYS_INDEPENDENT = FLAG_CATALOG.filter(
  (e) => e.plan_binding_type === 'independent'
).map((e) => e.flag_key);

// ========================
// Derived: Defaults
// ========================

export const DEFAULT_FEATURE_FLAGS: Record<string, TenantSettingDefaultValue> = Object.fromEntries(
  FLAG_CATALOG.map((e) => [e.flag_key, e.default_value])
);

export const DEFAULT_PLAN_BOUND_FEATURE_FLAGS: Record<string, TenantSettingDefaultValue> =
  Object.fromEntries(
    FLAG_CATALOG.filter((e) => e.plan_binding_type === 'plan_bound').map((e) => [
      e.flag_key,
      e.default_value,
    ])
  );

export const DEFAULT_INDEPENDENT_FEATURE_FLAGS: Record<string, TenantSettingDefaultValue> =
  Object.fromEntries(
    FLAG_CATALOG.filter((e) => e.plan_binding_type === 'independent').map((e) => [
      e.flag_key,
      e.default_value,
    ])
  );
